sql:
SELECT DISTINCT u.user_name 
FROM users u 
JOIN change_history ch ON u.user_id = ch.user_id;

SELECT assets.asset_id, assets.asset_name, asset_owners.user_id, asset_owners.assigned_at
FROM assets
JOIN asset_owners ON assets.asset_id = asset_owners.asset_id;

SELECT asset_id 
FROM change_history 
WHERE user_id = 1 AND action = 'U';

SELECT user_id, COUNT(rating_id) AS total_ratings
FROM asset_ratings
GROUP BY user_id;

SELECT assets.asset_id, assets.asset_name, asset_types.type_name
FROM assets
JOIN asset_types ON assets.asset_type = asset_types.type_id;

SELECT action, asset_id, timestamp 
FROM change_history 
ORDER BY timestamp DESC;

